import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Mic, MicOff, Play, Pause, Square, Loader2, Volume2, User, Bot } from 'lucide-react';
import { getLiveSession, encodeAudio, decodeAudio, decodeAudioData } from '../services/geminiService';

const SpeakingModule: React.FC = () => {
  const [isActive, setIsActive] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [transcript, setTranscript] = useState<{ sender: 'Examiner' | 'You', text: string }[]>([]);
  const [currentTranscription, setCurrentTranscription] = useState('');

  const audioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const streamRef = useRef<MediaStream | null>(null);
  const sessionPromiseRef = useRef<any>(null);

  const stopSession = useCallback(() => {
    setIsActive(false);
    setIsListening(false);
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
    }
    sourcesRef.current.forEach(source => source.stop());
    sourcesRef.current.clear();
  }, []);

  const startSession = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const inputCtx = new AudioContext({ sampleRate: 16000 });
      const outputCtx = new AudioContext({ sampleRate: 24000 });
      audioContextRef.current = outputCtx;

      const sessionPromise = getLiveSession({
        onopen: () => {
          setIsActive(true);
          setIsListening(true);

          const source = inputCtx.createMediaStreamSource(stream);
          const processor = inputCtx.createScriptProcessor(4096, 1, 1);

          processor.onaudioprocess = (e) => {
            const inputData = e.inputBuffer.getChannelData(0);
            const l = inputData.length;
            const int16 = new Int16Array(l);
            for (let i = 0; i < l; i++) {
              int16[i] = inputData[i] * 32768;
            }
            const pcmBlob = {
              data: encodeAudio(new Uint8Array(int16.buffer)),
              mimeType: 'audio/pcm;rate=16000',
            };

            sessionPromise.then((session: any) => {
              session.sendRealtimeInput({ media: pcmBlob });
            });
          };

          source.connect(processor);
          processor.connect(inputCtx.destination);
        },
        onmessage: async (msg: any) => {
          if (msg.serverContent?.outputTranscription) {
            setCurrentTranscription(prev => prev + msg.serverContent.outputTranscription.text);
          }

          if (msg.serverContent?.turnComplete) {
            setTranscript(prev => [...prev, { sender: 'Examiner', text: '...' }]); // Transcription support can be deeper
          }

          const audioData = msg.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
          if (audioData) {
            nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
            const buffer = await decodeAudioData(decodeAudio(audioData), outputCtx, 24000, 1);
            const source = outputCtx.createBufferSource();
            source.buffer = buffer;
            source.connect(outputCtx.destination);
            source.start(nextStartTimeRef.current);
            nextStartTimeRef.current += buffer.duration;
            sourcesRef.current.add(source);
          }
        },
        onerror: (e: any) => {
          console.error('Session Error:', e);
          stopSession();
        },
        onclose: () => {
          stopSession();
        }
      });

      sessionPromiseRef.current = sessionPromise;
    } catch (err) {
      console.error(err);
      alert('Could not access microphone.');
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-in zoom-in-95 duration-500">
      <div className="bg-white p-12 rounded-[2.5rem] shadow-sm border border-slate-100 text-center space-y-8 relative overflow-hidden">
        {/* Animated Background Pulse */}
        {isActive && (
          <div className="absolute inset-0 bg-indigo-50/50 animate-pulse pointer-events-none"></div>
        )}

        <div className="relative z-10">
          <div className="mb-8">
            <h2 className="text-3xl font-bold text-slate-800 mb-2">Speaking Mock Test</h2>
            <p className="text-slate-500">Simulate a real 1-on-1 IELTS interview with our AI examiner</p>
          </div>

          <div className="flex justify-center mb-12">
            <div className="relative">
              <div className={`w-40 h-40 rounded-full flex items-center justify-center transition-all duration-500 ${
                isActive ? 'bg-indigo-600 scale-110 shadow-xl shadow-indigo-200' : 'bg-slate-100'
              }`}>
                {isActive ? (
                  <Bot size={64} className="text-white animate-bounce" />
                ) : (
                  <User size={64} className="text-slate-300" />
                )}
              </div>
              {isActive && (
                <div className="absolute -bottom-2 -right-2 bg-green-500 p-3 rounded-full border-4 border-white text-white">
                  <Volume2 size={24} />
                </div>
              )}
            </div>
          </div>

          <div className="space-y-4">
            {!isActive ? (
              <button
                onClick={startSession}
                className="bg-indigo-600 text-white px-10 py-5 rounded-2xl font-bold text-xl flex items-center gap-3 mx-auto hover:bg-indigo-700 hover:scale-105 active:scale-95 transition-all shadow-lg shadow-indigo-200"
              >
                <Mic size={28} />
                Start Interview
              </button>
            ) : (
              <div className="flex flex-col items-center gap-6">
                <button
                  onClick={stopSession}
                  className="bg-rose-500 text-white px-10 py-5 rounded-2xl font-bold text-xl flex items-center gap-3 hover:bg-rose-600 active:scale-95 transition-all shadow-lg shadow-rose-200"
                >
                  <Square size={28} />
                  End Session
                </button>
                <div className="flex items-center gap-3 text-slate-500 animate-pulse">
                  <div className="w-2 h-2 bg-indigo-600 rounded-full"></div>
                  <span className="font-semibold uppercase tracking-widest text-sm">Examiner is Listening...</span>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Real-time Instructions / Tips */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
          <h4 className="font-bold text-slate-800 mb-2">Part 1: Intro</h4>
          <p className="text-sm text-slate-500 leading-relaxed">Relax and answer naturally about familiar topics like work, home, or hobbies.</p>
        </div>
        <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
          <h4 className="font-bold text-slate-800 mb-2">Part 2: Cue Card</h4>
          <p className="text-sm text-slate-500 leading-relaxed">Speak for 2 minutes. Use the 1 minute prep time to write down bullet points.</p>
        </div>
        <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
          <h4 className="font-bold text-slate-800 mb-2">Part 3: Discussion</h4>
          <p className="text-sm text-slate-500 leading-relaxed">Expand your answers. Discuss abstract ideas and justify your opinions clearly.</p>
        </div>
      </div>
    </div>
  );
};

export default SpeakingModule;

