                      <span className="text-6xl font-black">{feedback.overallBand}</span>
                      <span className="text-xl font-bold text-indigo-200">/ 9.0</span>
                    </div>
                  </div>
                  <div className="bg-white/10 backdrop-blur-md rounded-2xl p-6 border border-white/10">
                    <p className="text-sm text-indigo-100 mb-2">Score Analysis completed on</p>
                    <p className="font-bold">{new Date().toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' })}</p>
                  </div>
                </div>
              </div>

              {/* Criterion Accordion */}
              <div className="space-y-2">
                <h4 className="text-sm font-bold text-slate-400 uppercase tracking-widest ml-1 mb-3">Scoring Breakdown</h4>

                <AccordionItem
                  title="Task Response"
                  icon={<Target size={20} />}
                  isOpen={openSection === 'Task Response'}
                  onToggle={() => setOpenSection(openSection === 'Task Response' ? null : 'Task Response')}
                >
                  <p>{feedback.taskResponse}</p>
                </AccordionItem>

                <AccordionItem
                  title="Coherence & Cohesion"
                  icon={<Shuffle size={20} />}
                  isOpen={openSection === 'Coherence'}
                  onToggle={() => setOpenSection(openSection === 'Coherence' ? null : 'Coherence')}
                >
                  <p>{feedback.coherenceCohesion}</p>
                </AccordionItem>

                <AccordionItem
                  title="Lexical Resource"
                  icon={<Languages size={20} />}
                  isOpen={openSection === 'Lexical'}
                  onToggle={() => setOpenSection(openSection === 'Lexical' ? null : 'Lexical')}
                >
                  <p>{feedback.lexicalResource}</p>
                </AccordionItem>

                <AccordionItem
                  title="Grammatical Range & Accuracy"
                  icon={<FileCode size={20} />}
                  isOpen={openSection === 'Grammar'}
                  onToggle={() => setOpenSection(openSection === 'Grammar' ? null : 'Grammar')}
                >
                  <p>{feedback.grammaticalRange}</p>
                </AccordionItem>
              </div>

              {/* Suggested Corrections */}
              <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
                <div className="flex items-center gap-3 mb-6">
                  <div className="bg-emerald-100 p-2 rounded-lg text-emerald-600">
                    <CheckCircle2 size={20} />
                  </div>
                  <h4 className="text-lg font-bold text-slate-800">Suggested Improvements</h4>
                </div>
                <div className="space-y-4">
                  {feedback.suggestedCorrections.map((correction, i) => (
                    <div key={i} className="flex gap-4 p-5 bg-slate-50 rounded-2xl border border-slate-100 group hover:border-emerald-200 transition-colors">
                      <div className="bg-white w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold text-slate-400 group-hover:text-emerald-500 transition-colors shadow-sm shrink-0">
                        {i + 1}
                      </div>
                      <p className="text-slate-700 italic leading-relaxed">"{correction}"</p>
                    </div>
                  ))}
                </div>
              </div>

              {/* General IELTS Grammar Tips Section */}
              <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 border-t-4 border-t-amber-400">
                <div className="flex items-center gap-3 mb-6">
                  <div className="bg-amber-100 p-2 rounded-lg text-amber-600">
                    <Lightbulb size={20} />
                  </div>
                  <h4 className="text-lg font-bold text-slate-800">Common IELTS Grammar Tips</h4>
                </div>
                <div className="grid grid-cols-1 gap-4">
                  {grammarTips.map((item, index) => (
                    <div key={index} className="group">
                      <div className="flex items-start gap-4 p-4 rounded-2xl hover:bg-amber-50/50 transition-all border border-transparent hover:border-amber-100">
                        <div className="bg-slate-100 p-2 rounded-lg text-slate-400 group-hover:bg-amber-100 group-hover:text-amber-600 transition-colors">
                          <Info size={16} />
                        </div>
                        <div>
                          <p className="font-bold text-slate-800 mb-1">{item.title}</p>
                          <p className="text-sm text-slate-500 leading-relaxed">{item.tip}</p>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
                <div className="mt-8 p-5 bg-indigo-50 rounded-[1.5rem] flex items-center gap-4 border border-indigo-100">
                  <div className="w-10 h-10 bg-indigo-100 rounded-full flex items-center justify-center text-indigo-600 animate-pulse shrink-0">
                    <Info size={20} />
                  </div>
                  <p className="text-sm text-indigo-700 font-medium">
                    Pro-tip: Focus on accuracy first. A band 7 requires a high level of accuracy even in simple structures.
                  </p>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default WritingModule;
